import { AgendaService } from '../../services/agenda.service.js';
import type { AgendaList } from './agenda-list/agenda-list.component.js';
import './agenda-list/agenda-list.component.js';

export class AgendaScreen extends HTMLElement {
    private initialized = false;
    private agendaList!: AgendaList;
    private loadingEl!: HTMLElement;
    private errorEl!: HTMLElement;
    private retryBtn!: HTMLButtonElement;

    connectedCallback(): void {
        if (!this.initialized) {
            this.initialized = true;
            this.classList.add('view-section');
            this.id = 'agenda-view';
            this.buildDom();
        }
        void this.refresh();
    }

    private buildDom(): void {
        this.loadingEl = document.createElement('p');
        this.loadingEl.className = 'screen-loading';
        this.loadingEl.textContent = 'Loading agenda…';
        this.loadingEl.hidden = true;

        this.errorEl = document.createElement('pre');
        this.errorEl.className = 'screen-error';
        this.errorEl.dataset.testid = 'agenda-error';
        this.errorEl.hidden = true;

        this.retryBtn = document.createElement('button');
        this.retryBtn.type = 'button';
        this.retryBtn.className = 'screen-retry';
        this.retryBtn.dataset.testid = 'agenda-retry';
        this.retryBtn.textContent = 'Retry';
        this.retryBtn.hidden = true;
        this.retryBtn.addEventListener('click', () => { void this.refresh(); });

        this.agendaList = document.createElement('agenda-list') as AgendaList;

        this.append(this.loadingEl, this.errorEl, this.retryBtn, this.agendaList);
    }

    private async refresh(): Promise<void> {
        this.setLoading();
        try {
            const events = await AgendaService.fetchEvents();
            this.agendaList.events = events;
            this.clearStatus();
        } catch (err) {
            this.setError(err);
        }
    }

    private setLoading(): void {
        this.loadingEl.hidden = false;
        this.errorEl.hidden = true;
        this.retryBtn.hidden = true;
    }

    private setError(err: unknown): void {
        const message = err instanceof Error ? (err.stack ?? `${err.name}: ${err.message}`) : String(err);
        this.errorEl.textContent = `Failed to load agenda\n\n${message}`;
        this.errorEl.hidden = false;
        this.retryBtn.hidden = false;
        this.loadingEl.hidden = true;
    }

    private clearStatus(): void {
        this.loadingEl.hidden = true;
        this.errorEl.hidden = true;
        this.retryBtn.hidden = true;
    }
}

if (!customElements.get('agenda-screen')) {
    customElements.define('agenda-screen', AgendaScreen);
}
